import { v4 as uuidv4 } from "uuid";
import { Accordion as BSAccordion } from "react-bootstrap";

const Accordion = (props) => {
  const {
    AccordionContent,
    cssAccordion,
    cssAccordionItem,
    cssAccordionHeader,
    cssAccordionButton,
    cssAccordionBody,
  } = props;
  return (
    <BSAccordion defaultActiveKey="0" bsPrefix={"accordion " + cssAccordion}>
      {AccordionContent.map((e) => {
        // console.log(e)
        return (
          <BSAccordion.Item bsPrefix={"accordion-item " + cssAccordionItem}>
            <BSAccordion.Header
              bsPrefix={"accordion-header " + cssAccordionHeader}
            >
              {e.headerJSX}
            </BSAccordion.Header>
            <BSAccordion.Body bsPrefix={"accordion-body " + cssAccordionBody}>
              {e.bodyJSX}
            </BSAccordion.Body>
          </BSAccordion.Item>
        );
      })}
    </BSAccordion>
  );
};

export default Accordion;
