const universalDate = (dateIn, isMonthYearOnly) => {
  // console.log(dateIn)
  const dateN = new Date(dateIn)
  const tempDate = new Date(
    Date.UTC(
      dateN.getFullYear(),
      dateN.getMonth(),
      dateN.getDate(),
      dateN.getHours(),
      dateN.getMinutes(),
      dateN.getSeconds()
    )
  )
  return (isMonthYearOnly 
    ? new Intl.DateTimeFormat('en-US', { month: 'long' }).format(tempDate) + ' ' + tempDate.getFullYear()
    : new Intl.DateTimeFormat('en-US', { month: 'long' }).format(tempDate) + ' ' + tempDate.getDate() + ', ' + tempDate.getFullYear()
  )
}

export default universalDate
