// import shuffle from 'shuffle-array'
// import arrayShuffle from 'array-shuffle'

export default function arrayReducerStream (
  processor,
  key,
  minDisplayCount,
  // isShuffle
) {
  const outer = []
  let inner = []

  for (let i = 0; i < processor.length; i++) {
    if (i + 1 !== processor.length) {
      if (processor[i][key] === processor[i + 1][key]) {
        inner.push(processor[i])
      }
      if (processor[i][key] !== processor[i + 1][key]) {
        inner.push(processor[i])
        // if (isShuffle) {
        //  arrayShuffle(inner)
        // }
        if (minDisplayCount > 0) {
          outer.push(inner.slice(0, minDisplayCount))
        } else {
          outer.push(inner)
        }
        inner = []
      }
    } else if (i === processor.length - 1) {
      inner.push(processor[i])
      // if (isShuffle) {
      //   arrayShuffle(inner)
      // }
      if (minDisplayCount > 0) {
        outer.push(inner.slice(0, minDisplayCount))
      } else {
        outer.push(inner)
      }
      inner = []
    }
  }
  return outer
}
