

import { v4 as uuidv4 } from 'uuid'
import { OverlayTrigger, Tooltip as BSTooltip } from 'react-bootstrap';

const Tooltip = props => {
    const {
        tooltipText,
        tooltipPlacement,
        tooltipStyle,
        triggerJSX
    } = props
    return(<OverlayTrigger placement={tooltipPlacement} style={{textAlign:'left'}}
                overlay={<BSTooltip id={uuidv4()} >{tooltipText}</BSTooltip>}> 
                {triggerJSX} 
                </OverlayTrigger>)
}

export default Tooltip