export default function arrayRegexMatch (arrayIn, matchString) {
  const x = arrayIn.replace(new RegExp(' ', 'g'), '').split('|')
  let r = 0
  for (var k = 0; k < x.length; k++) {
    if (matchString.match(new RegExp(x[k], 'g'))) {
      r++
    } else {
      continue
    }
  }
  return r
}
