export default function getProfileStream (query, queryList, getResArea) {
  let valReturn = ''

  // console.log(query)
  // console.log(queryList)

  if (queryList !== undefined) {
    if (queryList.length !== 0) {
      valReturn = queryList.filter(function (e) {
        if (e.id_ntlogin === query.toLowerCase().trim()) {
          return e
        } else {
          return false
        }
      })[0]
      return valReturn !== undefined
        ? getResArea
          ? valReturn.labels_research_tid
          : valReturn
        : ''
    } else {
      return false
    }
  } else {
    return false
  }
}
