export default function arrayKeyExtract (arrayIn, key) {
  const r = []
  // console.log('key:', key)
  // console.log('matchString:', matchString)
  for (var k = 0; k < arrayIn.length; k++) { 
    if (arrayIn[k][key]) {
      // console.log('arrayIn[k][key]:', arrayIn[k][key])
      r.push(arrayIn[k][key])
    } else {
      continue
    }
  }
  // console.log(r)
  return r
}
