import { v4 as uuidv4 } from "uuid";
import { useState } from "react";

import {
  arrayReducerStream,
  arrayTwoReducerStream,
  arrayReducerSortOrderStream,
  textRegexClean,
  // TextHTMLDirectFilter,
  BBStyleCodeProcessor,
  cLog,
} from "../../common";
import {
  SMUSCISPROGRAMMES,
  genBSColumns,
  tracks2025Map,
} from "../../common/constants";
import CurriculumPanelCourse from "./CurriculumPanelCourse";
import { Modal } from "../../UIToolbox";

const CurriculumPanelMajorCore = (props) => {
  // const diagramSubDetails = true
  const {
    historic,
    viewMODE,
    dataCoreCourses,
    selectedFeatures,
    selectedMajorElectivesOptions,
    selectedSecondMajor,
    selectedSecondMajorTrackOption,
  } = props;
  // const is2017 = viewMODE.match(/(2017)/g); // TBR
  const feature_test_mode = viewMODE.match(/(z7kxjyucvp)/g);
  // const feature_test_secondMajors = viewMODE.match(/(ea0ed5e586)/g) || selectedFeatures.includes("ea0ed5e586");
  const feature_test_dbct = selectedFeatures.includes("a318b7e74f");

  viewMODE = viewMODE.match(/|/g) ? viewMODE.split("|")[0] : viewMODE;

  const is2019 = viewMODE.match(/(2019)/g); // TBR
  const isCL = viewMODE.match(/(CL2022)/g); // [TODO] UNLINK CL2022
  // const isSMT = viewMODE.match(/(SMT)/g);
  const isSMT22 =
    viewMODE.match(/(SMT2022)/g) || viewMODE.match(/(b45441be9)/g);
  const isCS19 = viewMODE.match(/(CS2019)/g); //CS2019
  const isU2XeCSbeCeVT = viewMODE.match(new RegExp("U2XeCSbeCeVT", "g"));
  const isCS2026 = viewMODE.match(new RegExp("CS2026", "g")); //CS2026
  const isFf4ca540 = viewMODE.match(/(c54681a11)/g); //SE2022
  const is_c31724904a7e = viewMODE.match(/(c31724904a7e)/g); // IS2023

  const totalCoursesMATRIX = (MATRIX) => {
    return MATRIX.map((f) => {
      return parseFloat(f.course_units);
    }).reduce((a, c) => {
      return a + c;
    });
  };
  const filtered = dataCoreCourses.filter((item) => {
    if (!item.course_name.match(new RegExp("Project Experience", "g"))) {
      return item;
    }
  });
  const filteredXP = dataCoreCourses.filter((item) => {
    if (item.course_name.match(new RegExp("Project Experience", "g"))) {
      return item;
    }
  });
  const selectedProg =
    viewMODE !== undefined ? SMUSCISPROGRAMMES.CoursesMapping[viewMODE] : "";
  const selectedProgKey =
    selectedProg !== undefined ? selectedProg.programme : "BSCISIS";
  const selectedPanelClass =
    selectedProg !== undefined
      ? selectedProg.panelClass
      : "curriculum is_foundations";
  // console.log('sProg:' + selectedProg)
  // console.log('sProgK:' + selectedProgKey)
  // console.log('sPanCl:' + selectedPanelClass)
  const filteredSorted =
    selectedProg !== undefined
      ? selectedProg.customOrder !== undefined
        ? arrayReducerSortOrderStream(
            filtered,
            "course_group",
            selectedProg.customOrder,
          )
        : filtered
      : filtered;
  const keyed = arrayReducerStream(filteredSorted, "course_group");
  const keyedMeta = arrayTwoReducerStream(
    filteredSorted,
    "course_group",
    "course_type",
  );
  console.log("selectedProg", selectedProg);
  console.log("selectedProgKey", selectedProgKey);
  console.log("filteredSorted", filteredSorted);
  console.log("selectedProg", selectedProg);
  console.log("selectedProgKey", selectedProgKey);
  console.log("keyed", keyed);
  console.log("keyedMeta", keyedMeta);
  const procCourseDbct = (k, j) => {
    const arr = k.split(",");
    return arr.some((e) => {
      // const trimmedValue = e.replace(/^[^:]*:(.*?)([ :])$/, "$1");
      const iViewMODE = viewMODE.match(/(U2XeCSbeCeVT)/g) ? "CS2019" : viewMODE;
      cLog(
        [
          "procCourseDbct",
          j,
          "e",
          e,
          // "trimmedValue", trimmedValue,
          "iViewMODE",
          iViewMODE,
          "tracks2025Map[selectedMajorElectivesOptions[0]",
          tracks2025Map[selectedMajorElectivesOptions[0]],
          "tracks2025Map[selectedMajorElectivesOptions[1]",
          tracks2025Map[selectedMajorElectivesOptions[1]],
          "tracks2025Map[selectedSecondMajorTrackOption[0]",
          tracks2025Map[selectedSecondMajorTrackOption[0]],
          "selectedSecondMajor",
          selectedSecondMajor,
        ],
        feature_test_mode,
      );
      return e.length > 0 && selectedSecondMajor.length > 0
        ? e.includes(":")
          ? (new RegExp(iViewMODE, "g").test(e) &&
              new RegExp(
                `#${tracks2025Map[selectedMajorElectivesOptions[0]]}`,
                "g",
              ).test(e)) ||
            (new RegExp(iViewMODE).test(e) &&
              new RegExp(
                `#${tracks2025Map[selectedMajorElectivesOptions[1]]}`,
                "g",
              ).test(e)) ||
            (new RegExp(iViewMODE).test(e) &&
              new RegExp(selectedSecondMajor, "g").test(e)) ||
            (new RegExp(selectedSecondMajor, "g").test(e) &&
              new RegExp(
                `#${tracks2025Map[selectedSecondMajorTrackOption[0]]}`,
                "g",
              ).test(e))
          : new RegExp(iViewMODE, "g").test(e) ||
            new RegExp(selectedSecondMajor, "g").test(e)
        : false;
    });
  };
  const procCourseDbctDisp = (y) => {
    // console.log("procCourseDbctDisp", y);
    return procCourseDbct(y.course_dbct, y.course_name) ? (
      <span className="badge bg-success">^</span>
    ) : (
      false
    );
  };
  // console.log(keyedMeta)
  const stdModuleModal = (e, showCourseCodeParentheses) => {
    // console.log(e);
    return (
      <CurriculumPanelCourse
        key={uuidv4()}
        courseName={
          e.course_description === "" ? (
            <span>
              {e.course_name}
              {showCourseCodeParentheses && !e.course_code.match(/\_/g)
                ? " (" + e.course_code + ") "
                : ""}
            </span>
          ) : (
            <Modal
              historic={historic}
              classMods=""
              buttonLabel={
                e.course_name +
                (showCourseCodeParentheses && !e.course_code.match(/\_/g)
                  ? " (" + e.course_code + ") "
                  : "")
              }
              notButtonTextOnly
              buttonLarge
              buttonInvert={false}
              buttonHref={
                "#" +
                textRegexClean(e.course_name, "underscore") +
                "_" +
                viewMODE
              }
              title={
                (e.course_code && !e.course_code.match(/\_/g)
                  ? e.course_code + " : "
                  : "") + e.course_name
              }
              content={
                <div className="p-3">
                  {e.course_group ? (
                    <div>
                      <strong>Course Group :</strong> {e.course_group}
                      <hr className="my-1" />
                    </div>
                  ) : (
                    ""
                  )}
                  <BBStyleCodeProcessor textIn={e.course_description} />
                </div>
              }
              isBSModal
            />
          )
        }
        courseLabel={
          e.course_units + " CU" + (parseFloat(e.course_units) > 1 ? "s" : "")
        }
        courseSuffix={feature_test_dbct ? procCourseDbctDisp(e) : false}
        courseCardClass={"sgsmuscis-ug-curriculum-major-electives-modal"}
      />
    );
  };
  const mods2019wXP = keyed.map((mod) => {
    return (
      <div
        key={uuidv4()}
        className={
          (isCS19 || isU2XeCSbeCeVT || isCS2026 || is_c31724904a7e || isCL
            ? genBSColumns("6", "6", "12", "12")
            : "") +
          (isSMT22 || isFf4ca540 ? genBSColumns("4", "4", "12", "12") : "") +
          " px-2"
        }
      >
        <CurriculumPanelCourse
          key={uuidv4()}
          courseName={<span>{mod[0].course_group}</span>}
          courseLabel={
            <label className=" float-end ">{totalCoursesMATRIX(mod)} CUs</label>
          }
          courseLabelClass={"bg-sis"}
          courseDescriptionJSX={
            <div className="row">
              <div className="col-lg-12 col-md-12 col-sm-12 col-xs-12">
                {mod.map((e) => {
                  return stdModuleModal(e, true);
                })}
              </div>
            </div>
          }
        />
      </div>
    );
  });
  const modsCL2020wXP = keyedMeta.map((type, i) => {
    // console.log(type)
    return (
      <div key={uuidv4()} className="col-lg-6 col-md-6 col-sm-6 col-xs-12 px-2">
        <div className="row">
          <div className="col-lg-12 col-md-12 col-sm-12 col-xs-12">
            {type.map((mod) => {
              return (
                <CurriculumPanelCourse
                  key={uuidv4()}
                  courseName={<span>{mod[0].course_group}</span>}
                  courseLabel={totalCoursesMATRIX(mod) + " CUs"}
                  courseLabelClass={"bg-sis"}
                  courseDescriptionJSX={
                    <div className="row">
                      <div className="col-lg-12 col-md-12 col-sm-12 col-xs-12">
                        {mod.map((e) => {
                          return stdModuleModal(e, true);
                        })}
                      </div>
                    </div>
                  }
                  coursePanelClass={
                    type[0][0].course_type === "COMP" ? "" : "-dpurple "
                  }
                />
              );
            })}
          </div>
        </div>
      </div>
    );
  });
  const modsFf4ca540 = keyed.map((mod) => {
    return (
      <div
        key={uuidv4()}
        className={"col-lg-4 col-md-4 col-sm-12 col-xs-12 px-2"}
      >
        <CurriculumPanelCourse
          key={uuidv4()}
          courseName={<span>{mod[0].course_group}</span>}
          courseLabel={totalCoursesMATRIX(mod) + " CUs"}
          courseLabelClass={"bg-sis"}
          courseDescriptionJSX={
            <div className="row">
              <div className="col-lg-12 col-md-12 col-sm-12 col-xs-12">
                {mod.map((e) => {
                  return stdModuleModal(e, true);
                })}
              </div>
            </div>
          }
        />
      </div>
    );
  });

  return (
    <div className={genBSColumns("12", "12", "12", "12") + " pb-2"}>
      <div
        className={
          " card background " +
          selectedPanelClass +
          " margin-clear accordion-item"
        }
      >
        <div className="accordion-header">
          <a
            className="accordion-button bg-transparent flex-grow-1 px-2 py-0 m-0"
            data-bs-toggle="collapse"
            data-bs-target="#sgsmuscis_curriculum_FirstMajorCore"
          >
            <div
              className="card-header p-2 d-flex flex-grow-1 align-items-center bg-transparent"
              style={{ borderBottom: "none" }}
            >
              <h4
                className={
                  "py-1 m-0 flex-grow-1 " +
                  (selectedProgKey === "BSCISIS" ||
                  selectedProgKey === "d6371b8be0eb"
                    ? "text-grey-dark"
                    : "text-white")
                }
              >
                {SMUSCISPROGRAMMES.CoursesMapping[viewMODE].coreName +
                  " Major Core"}
              </h4>
              <span className="badge bg-gold">
                {selectedProgKey === "c54681a11" || isSMT22 ? "12 CUs" : ""}
                {is2019 || isCL || isCS2026 || is_c31724904a7e ? (
                  <>
                    {totalCoursesMATRIX(dataCoreCourses)} CU
                    {totalCoursesMATRIX(dataCoreCourses) > 1 ? "s" : ""}
                  </>
                ) : (
                  ""
                )}
              </span>
            </div>
          </a>
        </div>
        <div
          className="card-body p-0 accordion-collapse collapse show"
          id="sgsmuscis_curriculum_FirstMajorCore"
        >
          <div className="row">
            <div className={genBSColumns("12", "12", "12", "12")}>
              <div className="p-2">
                <div className={"card text-center p-2 "}>
                  <div className="row">
                    {/*is2017 ? <>{mods2017wXP}</> : ""*/}
                    {is2019 || isCS2026 || isSMT22 || is_c31724904a7e ? (
                      <>{mods2019wXP}</>
                    ) : (
                      ""
                    )}
                    {isCL ? <>{modsCL2020wXP}</> : ""}
                    {isFf4ca540 ? <>{modsFf4ca540}</> : ""}
                    {isFf4ca540 ? (
                      ""
                    ) : (
                      <div
                        className={
                          genBSColumns("12", "12", "12", "12") + " px-2"
                        }
                      >
                        {filteredXP.map((e) => {
                          // console.log('filteredXP', e)
                          return (
                            <CurriculumPanelCourse
                              key={uuidv4()}
                              courseName={<span>{e.course_name}</span>} // courseCode={e.course_code}
                              courseLabel={
                                e.course_units +
                                " CU" +
                                (parseFloat(e.course_units) > 1 ? "s" : "")
                              }
                              courseLabelClass={"bg-sis"}
                              courseDescriptionJSX={
                                e.course_description ? (
                                  <div className={"p-2 text-left"}>
                                    <BBStyleCodeProcessor
                                      textIn={e.course_description}
                                    />
                                  </div>
                                ) : (
                                  ""
                                )
                              }
                              coursePanelClass="text-center"
                            />
                          );
                        })}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CurriculumPanelMajorCore;
