export default function textRegexClean (input, option) {
  const output =
    typeof input === 'string'
      ? (option === 'underscore'
        ? input
          .trim()
          .toLowerCase()
          .replace(/[.]/g, '_')
          .replace(/[,]/g, '_')
          .replace(/\s/g, '_')
          .replace(/ /g, '_')
          .replace(/[&]/g, '')
          .replace(/[?]/g, '')
          .replace(/[!]/g, '')
          .replace(/[:]/g, '')
          .replace(/[@]/g, '')
          .replace(/[(]/g, '')
          .replace(/[)]/g, '')
          .replace(/["]/g, '')
          .replace(/[\/]/g, '')
        : '') +
        (option === 'hyphen'
          ? input
            .trim()
            .toLowerCase()
            .replace(/[.]/g, '-')
            .replace(/[,]/g, '-')
            .replace(/\s/g, '-')
            .replace(/ /g, '-')
            .replace(/[&]/g, '')
            .replace(/[?]/g, '')
            .replace(/[!]/g, '')
            .replace(/[:]/g, '')
            .replace(/[@]/g, '')
            .replace(/[(]/g, '')
            .replace(/[)]/g, '')
            .replace(/["]/g, '')
            .replace(/[\/]/g, '')
          : '')
      : ''
  return output === '' ? false : output
}
