export default function arrayReducerSortOrderStream (
  processor,
  key,
  orderArray
) {
  // console.log('p:' + processor)
  // console.log('k:' + key)
  // console.log('o:' + orderArray)
  const cSortInner = []
  // In view of https://bugs.chromium.org/p/v8/issues/detail?id=164 , one has to
  // switch to .map() instead of for loop to preserve property array ordering
  orderArray.map(k => {
    // console.log(k)
    processor.map(e => {
      if (e[key] === k) {
        // console.log(e)
        cSortInner.push(e)
      }
    })
  })
  return cSortInner
}
