export default function arrayTwoReducerStream (processor, key, metakey) {
  const outer = []
  let collapseMeta = []
  let inner = []
  for (let i = 0; i < processor.length; i++) {
    if (i + 1 !== processor.length) {
      if (processor[i][key] === processor[i + 1][key]) {
        inner.push(processor[i])
      } else if (processor[i][key] !== processor[i + 1][key]) {
        inner.push(processor[i])
        collapseMeta.push(inner)
        inner = []

        if (processor[i][metakey] !== processor[i + 1][metakey]) {
          outer.push(collapseMeta)
          collapseMeta = []
        }
      }
    } else if (i === processor.length - 1) {
      inner.push(processor[i])
      collapseMeta.push(inner)
      inner = []
      outer.push(collapseMeta)
      collapseMeta = []
    }
  }
  return outer
}
