import React, { useState, useEffect } from "react";

import { checkLocalhost } from "./common";
import components from "./components";
import {
  SCISReactUniversalis_keyTree,
  baseJSONSTREAMURLs,
  JSONDBSTREAMMAP,
} from "./common/constants";

const useDataApi = (
  initialRequestKeys,
  initialData,
  ImportGDOC,
  loadJSONfrRed,
) => {
  const [data, setData] = useState(initialData);
  const [requestKeys, setRequestKeys] = useState(initialRequestKeys);
  const [isLoading, setIsLoading] = useState(false);
  const [isError, setIsError] = useState(false);

  useEffect(() => {
    const fetchData = async (requestKey, ImportGDOC) => {
      setIsError(false);
      setIsLoading(true);
      const baseJSONURL = checkLocalhost()
        ? baseJSONSTREAMURLs[3]
        : loadJSONfrRed
          ? baseJSONSTREAMURLs[1]
          : baseJSONSTREAMURLs[0];
      const loadURL = baseJSONURL + JSONDBSTREAMMAP[requestKey] + ".json";

      console.log('loadURL', loadURL)
      try {
        const response = await fetch(loadURL);
        const result = { data: await response.json() };

        // console.log('inside', data)
        let pResult = {};
        pResult = { [requestKey]: result.data };
        setData((data) => ({ ...data, ...pResult }));
      } catch (error) {
        let pErrorMsg = "\n loadURL | " + loadURL;
        if (error.response) {
          pErrorMsg += "\n error.response.status | " + error.response.status;
        } else if (error.request) {
          pErrorMsg += "\n error.request.status | " + error.request.status;
        } else {
          pErrorMsg += "\n error.message | " + error.message;
        }
        console.log(pErrorMsg);
        setIsError(true);
      }
      setIsLoading(false);
    };
    // console.log('requestKeys', requestKeys)
    requestKeys.map((requestKey) => {
      if (requestKey) {
        fetchData(requestKey, ImportGDOC);
      }
    });
  }, []);
  return [{ data, isLoading, isError }, setRequestKeys];
};
const SCISReactUniversalisTXU = (props) => {
  const { options, historic } = props;
  const keyString = [
    "Profiles",
    "TaxonomyResAreasStream",
    "TaxonomyResAreasStreamNX",
    "PROGRAMMES_THEMES_TRACKS",
    "PROGRAMMES_COURSES",
    SCISReactUniversalis_keyTree[options.selectDATATYPE] !== undefined
      ? SCISReactUniversalis_keyTree[options.selectDATATYPE][
          options.selectCLASS
        ] !== undefined
        ? SCISReactUniversalis_keyTree[options.selectDATATYPE][
            options.selectCLASS
          ] === "bypass"
          ? false
          : SCISReactUniversalis_keyTree[options.selectDATATYPE][
              options.selectCLASS
            ]
        : false
      : false,
  ];
  const [{ data, isLoading, isError }, doFetch] = useDataApi(
    keyString,
    {
      LISTINGS_ALL_TEST: [],
      LISTINGS_PG_RESEARCH_PUBLICATIONS: [],
      LISTINGS_RESSEM_CONF_PART: [],
      LISTINGS_RESSEM_EXTERNAL: [],
      LISTINGS_RESSEM_INTERNAL: [],
      PROFILES_UG_AWARDS: [],
      Profiles: [],
      PROGRAMMES_COURSES: [],
      PROGRAMMES_THEMES_TRACKS: [],
      TaxonomyResAreasStream: [],
      TaxonomyResAreasStreamNX: [],
    },
    false,
    options.selectCLASS === "IMPORTGDOC" ? options.selectAREA : undefined,
    options.dataJSONMIRROR === "a99627d2654",
  );

  return (
    <div id="react-main-app">
      {isError && (
        <div>
          Error: Check streamline data loading, please refresh, if you still see
          this, email scis_tech [at] smu.edu.sg
        </div>
      )}
      {isLoading ? (
        <div>Loading...</div>
      ) : (
        <>
          {data.Profiles.length !== 0 ? (
            data.TaxonomyResAreasStream.length !== 0 ? (
              data.TaxonomyResAreasStreamNX.length !== 0 ? (
                data.PROGRAMMES_THEMES_TRACKS.length !== 0 ? (
                  data.PROGRAMMES_COURSES.length !== 0 ? (
                    components(data, options, historic)
                  ) : (
                    <div>Loading...</div>
                  )
                ) : (
                  <div>Loading...</div>
                )
              ) : (
                <div>Loading...</div>
              )
            ) : (
              <div>Loading...</div>
            )
          ) : (
            <div>Loading...</div>
          )}
        </>
      )}
    </div>
  );
};

export default SCISReactUniversalisTXU;
