// TODO | genBSColumns conversion

const PanelListElement = props => {
  const {
    cardID,
    cardColor,
    cardHeader,
    cardHeight,
    cardHalfWidth,
    cardThirdWidth,
    cardFourthWidth,
    cardFifthWidth,
    cardVertical,
    cardFilterOptions,
    // cardHeading,
    cardBodyHeader,
    cardLeftJSX,
    cardCenterJSX,
    cardBodySubFooter,
    // cardBodySubFooterColTwelve,
    cardRightJSX,
    cardBodyFooter,
    cardFooter,
    cardMobileGridLock,
    cardGridExpand,
    // , 
    cardLink,
    mapped
  } = props

  // console.log(mapped)
  const classPanelCard = 'card h-100 rounded-3'
    + (mapped ? cardColor(mapped) : cardColor) + ' '
  // console.log(cardHeader)
  const coreElement = <div className={classPanelCard} id={cardID}>
    {cardHeader ? <div className={'card-header p-0'}> {cardHeader} </div> : ''}
    <div className={'card-body p-2 m-0'}>
      <div className='row align-items-top'>
        {cardBodyHeader ? <div className='col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12'>{cardBodyHeader}</div> : ''}
        <div className={cardVertical ? 'col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12'
          : cardRightJSX
            ? 'col-xl-3 col-lg-3 col-md-3 col-sm-3 col-xs-12'
            : cardMobileGridLock
              ? 'col-xl-4 col-lg-4 col-md-4 col-sm-4 col-xs-3'
              : cardGridExpand ? 'col-xl-3 col-lg-3 col-md-3 col-sm-3 col-xs-3' : 'col-xl-4 col-lg-4 col-md-4 col-sm-12 col-xs-12'}>
          {mapped ? cardLeftJSX(mapped) : cardLeftJSX}
        </div>
        <div className={cardCenterJSX ? cardVertical ? 'col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12'
          : cardRightJSX ? 'col-xl-6 col-lg-6 col-md-6 col-sm-6 col-xs-12'
            : cardMobileGridLock ? 'col-xl-8 col-lg-8 col-md-8 col-sm-8 col-xs-9' : 'col-xl-8 col-lg-8 col-md-8 col-sm-12 col-xs-12'
          : cardGridExpand ? 'col-xl-9 col-lg-9 col-md-9 col-sm-9 col-xs-9' : 'col-xl-10 col-lg-10 col-md-10 col-sm-10 col-xs-12'}>
          {mapped ? cardCenterJSX(mapped) : cardCenterJSX}
        </div>
        {cardRightJSX ? <div className={cardVertical ? 'col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12' : 'col-xl-3 col-lg-3 col-md-3 col-sm-3 col-xs-12'}>
          {mapped ? cardRightJSX(mapped) : cardRightJSX}</div>
          : ''}
        {cardBodySubFooter ? <div className='col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12'>{cardBodySubFooter}</div> : ''}
        {cardBodyFooter ? <div className='col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12'>{cardBodyFooter}</div> : ''}
      </div>
    </div>
    {cardFooter ? <div className="card-footer p-2">{cardFooter}</div> : ''}
  </div>

  return (<div className={' my-2  ' +
    (cardFilterOptions !== undefined ? cardFilterOptions : ' ') +
    (cardHalfWidth
      ? 'col-xl-6 col-lg-6 col-md-6 col-sm-6 col-xs-12 '
      : cardThirdWidth
        ? 'col-xl-4 col-lg-4 col-md-4 col-sm-4 col-xs-12 '
        : cardFourthWidth
          ? 'col-xl-3 col-lg-3 col-md-3 col-sm-4 col-xs-12'
          : cardFifthWidth
            ? 'col-xs-5ths col-sm-5ths col-md-5ths col-lg-5ths '
            : 'col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12 ')}>
    {cardLink
      ? <a target='_blank' href={cardLink}>{coreElement}</a>
      : <>{coreElement}</>}
  </div>)
};
export default PanelListElement
