import { arrayKeyExtract, arrayReducerSortOrderStream } from '../common'

const ResearchAreasIntegrated = props => {

    const { query, TaxonomyResAreas, TaxonomyResAreasNX, viewFormat } = props

    const componentClass =
        viewFormat === 'list_text'
            ? ' text-left'
            : viewFormat === 'block'
                ? 'add-border-radius-5px padding-vertical-5 text-left background height-45px '
                : 'text-left '

    const regenTokenList = [
        ...query.trim().replace(/ /g, '').split(','),
        ...query.trim().replace(/ /g, '').split(',').map((token) => {
            return token.replace(new RegExp('[0-9]', 'g'), '0')
        })]

    const unique = [...new Set(regenTokenList)]

    const taxRA = unique.map((f) => { return TaxonomyResAreas.filter((e) => { return (e.label_research_tid === f && e.order === '0') })[0] })
    const taxRANX = unique.map((f) => { return TaxonomyResAreasNX.filter((e) => { return (e.id_research_ref === f) })[0] })

    const taxRAde = taxRA.filter((k) => { return (k !== undefined && k.length !== 0) })
    const taxRANXde = taxRANX.filter((k) => { return (k !== undefined && k.length !== 0) })

    const sortTaxRAArr = arrayKeyExtract(TaxonomyResAreas, 'label_research_tid')
    const sortTaxRANXArr = arrayKeyExtract(TaxonomyResAreasNX, 'id_research_ref')

    const taxRAdar = arrayReducerSortOrderStream(taxRAde, 'label_research_tid', sortTaxRAArr)
    const taxRANXdar = arrayReducerSortOrderStream(taxRANXde, 'id_research_ref', sortTaxRANXArr)

    // console.log('unique', unique, 'taxRAdar', taxRAdar, 'taxRANXdar', taxRANXdar)

    const resAreaNXList = taxRANXdar.map((e) => {
        return (<> {e.datatype === 'parent' ? <li>{e.value}</li> : ''}
            {e.datatype === 'term' ? <li style={{ listStyleType: 'none' }}><ul><li>{e.value}</li></ul></li> : ''} </>)
    })
    const resAreaList = taxRAdar.map((e) => { return (<li>{e.value}</li>) })

    return (viewFormat === 'block'
        ? <div className={componentClass}> <ul >{resAreaNXList}{resAreaList}</ul> </div>
        : <span className={componentClass}><ul >{resAreaNXList}{resAreaList}</ul></span>)
};
export default ResearchAreasIntegrated
