import arrayRegexMatch from './arrayRegexMatch'

export default function universalFilterY (
  processor,
  selectAREA,
  selectSUBCLASS,
  selectSTATUS,
  selectUSERNAME,
  numberITEMSEACH,
  selectSUBTYPES
) {
  // console.log('inside universalFilterY', {processor})
  // console.log('universalFilterX')
  return processor
    .filter(entry => {
      if (selectAREA && selectSUBCLASS && selectSUBTYPES && selectSTATUS) {
        return (
          entry.metatype === selectAREA &&
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g')) &&
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1] &&
          arrayRegexMatch(entry.label_subtypes, selectSUBTYPES) &&
          entry.labels_status === selectSTATUS
        )
      } else if (selectAREA && selectSUBCLASS && selectSUBTYPES && selectUSERNAME) {
        return (
          entry.metatype === selectAREA &&
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g')) &&
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1] &&
          arrayRegexMatch(entry.label_subtypes, selectSUBTYPES) &&
          entry.id_ntlogin === selectUSERNAME
        )
      } else if (selectAREA && selectSUBCLASS && selectSUBTYPES) {
        return (
          entry.metatype === selectAREA &&
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g')) &&
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1] &&
          arrayRegexMatch(entry.label_subtypes, selectSUBTYPES)
        )
      } else if (selectAREA && selectSUBCLASS && selectSTATUS) {
        return (
          entry.metatype === selectAREA &&
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g')) &&
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1] &&
          entry.labels_status === selectSTATUS
        )
      } else if (selectAREA && selectSUBCLASS) {
        return (
          entry.metatype === selectAREA &&
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g'))
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1]
        )
      } else if (selectAREA && selectUSERNAME) {
        return (
          entry.metatype === selectAREA && entry.id_ntlogin === selectUSERNAME
        )
      } else if (selectAREA && selectSTATUS) {
        return (
          entry.metatype === selectAREA && entry.labels_status === selectSTATUS
        )
      } else if (selectAREA) {
        return entry.metatype === selectAREA
      } else if (selectSUBCLASS && selectSTATUS) {
        return (
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g')) &&
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1] && 
          entry.labels_status === selectSTATUS
        )
      } else if (selectSUBCLASS) {
        return (
          selectSUBCLASS.split('|')[1].match(new RegExp(entry[selectSUBCLASS.split('|')[0]],'g'))
          // entry[selectSUBCLASS.split('|')[0]] === selectSUBCLASS.split('|')[1]
        )
      } else if (selectSTATUS) {
        return entry.labels_status === selectSTATUS
      } else if (selectUSERNAME) {
        return entry.id_ntlogin === selectUSERNAME
      } else {
        return entry
      }
    })
    .slice(0, numberITEMSEACH !== '' ? numberITEMSEACH : processor.length)
}
