import { v4 as uuidv4 } from 'uuid'
// import { Popover, OverlayTrigger } from 'react-bootstrap'

import { arrayTwoReducerStream, arraySubkeyRegexMatch, arraySortAsc, textRegexClean } from '../common'
import IntegratedProfiles from '../Profiles/IntegratedProfiles'
import { genBSColumns, IMGPath } from '../common/constants'
import { Modal } from '../UIToolbox'

const ResearchAreasGridNX = props => {
  const {
    taxonomyResAreas,
    selectAREA,
    historic,
    profiles,
    viewMODE
  } = props 
  const mapping = elem => {
    return {
      metatype: elem.metatype,
      shortcode: elem.shortcode,
      datatype: elem.datatype,
      key: elem.key,
      order: elem.order,
      value: elem.value,
      value_sep24: elem.value_sep24,
      value_details: elem.value_details
    }
  }
  // console.log(arrayTwoReducerStream(taxonomyResAreas, 'key', 'metatype'))
  return (
    <div>
      {selectAREA !== '' ? (
        <div className='row'>
          {taxonomyResAreas
            .filter(e => {
              return e.key === selectAREA
            })
            .filter(f => {
              return f.datatype === 'term'
            })
            .map(k => {
              return (<div key={uuidv4()} className={genBSColumns('3', '3', '3', '12')}>
                <div
                  className={'height-65px box-percent-95 subresarea text-center ' + k.key +
                    ' border margin-vertical-5 add-border-radius-8px'} style={{ background: '#F1F1F1' }}
                >
                  <div className='padding-5' style={{ lineHeight: '14px' }}>
                    {k.value}
                  </div>
                </div>
              </div>
              )
            })}
        </div>
      ) : (
        arrayTwoReducerStream(taxonomyResAreas, 'key', 'metatype').map(
          (entry, k) => {
            const sectionResAreas = entry.map(function (resAreaElems, j) {
              // console.log(resAreaElems)
              const panels = resAreaElems.map(function (elem, i) {
                // console.log(elem, i);
                // console.log(mapping)
                // const map = mapping(elem)

                const profilesFaculty = arraySubkeyRegexMatch(profiles, 'datatype', 'FACULTY')
                const profilesMatchPResArea = (viewMODE.match(/(SEP2024)/g) 
                  ? arraySubkeyRegexMatch(profilesFaculty, 'research_primary_sep24', elem.value_sep24)
                  : arraySubkeyRegexMatch(profilesFaculty, 'research_tid_primary', elem.research_tid))
                // const profilesFilterFacultyStreamTrack = arrayReducerStream(profilesMatchPResArea, 'label_subtype', false, false)
                // console.log('profilesMatchPResArea', profilesMatchPResArea);
                const valueTitle = viewMODE.match(/(SEP2024)/g) ? elem.value_sep24 : elem.value
                return (
                  <>
                    {i !== 0 ? (
                      <div className={(resAreaElems[0].metatype === 'CORE' ? 'height-45px' : 'height-70px')
                        + ' subresarea text-center ' + elem.key + ' list-group-item '}
                        style={{}}
                        title={elem.value_details}>
                        {viewMODE.match(/modalProfiles/g) && profilesMatchPResArea.length > 0
                          ? <div className="text-left">
                            <Modal 
                              historic={historic}
                              buttonLabel={valueTitle}
                              buttonHref={'#' + 'smu_scis_research_' + 
                                textRegexClean(valueTitle, 'underscore')}
                              buttonLarge
                              notButtonTextOnly
                              title={valueTitle}
                              content={<div className='p-2'>
                                <div className="row">
                                  <IntegratedProfiles
                                    historic={historic}
                                    viewFormat={'mini|160px|fourth|grid|' + elem.metatype}
                                    selectAREA='FACULTY'
                                    selectSUBCLASS={viewMODE.match(/(SEP2024)/g) 
                                      ? 'research_primary_sep24|' + elem.value_sep24
                                      : 'research_tid_primary|' + elem.research_tid}
                                    selectSTATUS='current'
                                    Profiles={arraySortAsc(profilesMatchPResArea, 'name_last')}
                                    TaxonomyResAreasStream={taxonomyResAreas}
                                    tokenList={false}
                                  />
                                </div>
                              </div>}
                              queryTransfer={false}
                              isBSModal={true}
                            />
                          </div>
                          : <div className="text-left">{valueTitle}</div>}
                      </div>) : ''}
                  </>
                )
              })
              // console.log(viewMODE)
              const resAreaElemsValue = viewMODE.match(/(SEP2024)/g) ? resAreaElems[0].value_sep24 : resAreaElems[0].value
              return (<div className={resAreaElems[0].metatype === 'CORE'
                ? genBSColumns('4', '4', '4', '12') + ((j + 1) % 3 === 0 ? '' : ' add-border-right-dgrey-1px')
                : genBSColumns('3', '3', '3', '12') + ((j + 1) % 4 === 0 ? '' : ' add-border-right-dgrey-1px')}
                key={uuidv4()}>
                <div className={(resAreaElems[0].metatype === 'CORE' ? '' : ' ' + resAreaElems[0].key) + ' '}>
                  <div className='row align-items-center text-center height-70px'>
                    <div className={genBSColumns('4', '4', '4', '12') + 'p-0'}>
                      <img className='img-fluid text-center' alt={resAreaElemsValue}
                        src={'/sites/scis.smu.edu.sg/files/2023-07/' + textRegexClean(resAreaElems[0].value, 'hyphen') + '.png'} />
                    </div>
                    <div className={genBSColumns('8', '8', '8', '12')}>
                      <p className='text-left'>
                        <strong>{resAreaElemsValue}</strong>
                      </p>
                    </div>
                  </div>
                  <div className='row'>
                    <div className={genBSColumns('12', '12', '12', '12')}>
                      <div className='list-group p-2 padding-10 p-2'>{panels}</div>
                    </div>
                  </div>
                </div>
              </div>)
            })
            return (<div key={uuidv4()} id='smu-scis-research-overview'
              className='row smu-scis-research-overview'>
              {entry[0][0].metatype === 'CORE'
                ? <>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    <h4 className='margin-clear p-2' style={{ padding: '5px 5px 7px 5px' }}>
                      CORE RESEARCH AREAS - CREATE COMPUTING TECHNOLOGY AND SYSTEMS
                    </h4>
                  </div>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    &nbsp;
                  </div>
                  <div className={'row align-items-bottom'}
                    id='collapse-CORE'>
                    {sectionResAreas}
                  </div>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    &nbsp;
                  </div>
                </>
                : ''}
              {entry[0][0].metatype === 'INTEGRATIVE'
                ? <>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    <h4 className='margin-clear p-2' style={{ padding: '5px 5px 7px 5px' }}>
                      INTEGRATIVE RESEARCH AREAS - DIGITAL TRANSFORMATION IN ACTION
                    </h4>
                  </div>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    &nbsp;
                  </div>
                  <div className={'row align-items-bottom'}
                    id='collapse-INTEGRATIVE'>
                    {sectionResAreas}
                  </div>
                  <div className={genBSColumns('12', '12', '12', '12')}>
                    &nbsp;
                  </div>
                </>
                : ''}
            </div>
            )
          }
        )
      )}
    </div>
  )
}

export default ResearchAreasGridNX
