import { useState } from "react";
import { genIconDirect } from "../common/constants";
import { Modal as BSModal } from "react-bootstrap";

const ModalHooks = (props) => {
  const {
    historic,
    buttonClass,
    notButtonTextOnly,
    buttonHref,
    buttonLabelJSX,
    buttonLabel,
    title,
    titleHidden,
    content,
  } = props;

  const removeHash = (historic) => {
    // @see https://stackoverflow.com/questions/1397329/how-to-remove-the-hash-from-window-location-url-with-javascript-without-page-r

    let history = historic;
    // console.log('historic bef', history);
    var scrollV,
      scrollH,
      loc = history.location;

    //if ("pushState" in history.state)
    //  history.push(history.location.pathname, { some: "pushState" });
    //else {
    // Prevent scrolling by storing the page's current scroll offset
    scrollV = document.body.scrollTop;
    scrollH = document.body.scrollLeft;
    history.replace({
      pathname: window.location.origin + history.location.pathname,
      hash: "",
    });
    // console.log('history aft', history);
    // Restore the scroll offset, should be flicker free
    document.body.scrollTop = scrollV;
    document.body.scrollLeft = scrollH;
    //}
  };
  const [modalShow, setModalShow] = useState(false);

  return (
    <>
      <a
        className={
          buttonClass ||
          (notButtonTextOnly ? "" : "btn btn-sm btn-block bg-sis mb-2")
        }
        href={buttonHref}
        onClick={() => setModalShow(true)}
      >
        {buttonLabelJSX || (
          <span>
            {notButtonTextOnly ? genIconDirect("fa-expand-arrows-alt") : ""}
            &nbsp;{buttonLabel}&nbsp;
            {notButtonTextOnly ? "" : genIconDirect("fa-expand-arrows-alt")}
          </span>
        )}
      </a>
      <BSModal
        show={modalShow}
        onHide={() => {
          setModalShow(false);
          removeHash(historic);
        }}
        size="xl"
        centered
        aria-labelledby="contained-modal-title-vcenter"
        style={{ border: "solid 2px #c69200;" }}
      >
        {titleHidden ? (
          ""
        ) : (
          <BSModal.Header className="py-2 px-3" closeButton>
            <h5 className="m-0">{title}</h5>
          </BSModal.Header>
        )}
        <BSModal.Body className="p-0"> {content} </BSModal.Body>
      </BSModal>
    </>
  );
};

export default ModalHooks;
