import { v4 as uuidv4 } from "uuid";

import { textRegexClean } from "../../common";
import TextHTMLDirectFilter from "../../common/TextHTMLDirectFilter";
import { genIconDirect } from "../../common/constants";
import { Accordion } from "../../UIToolbox";

const CurriculumPanelCourse = (props) => {
  const {
    courseName,
    courseSupNum,
    courseCode,
    courseDescription,
    courseDescriptionJSX,
    courseLink,
    courseLabel,
    courseLabelPrefix,
    courseLabelPrefixClass,
    courseSuffix,
    courseCardClass,
    courseCardCollapse,
    courseLabelClass,
    courseCodeAsDataAttribute,
  } = props;

  // console.log("courseCardCollapse", courseCardCollapse);

  const curriculumPanelCourse_cardHeader = (
    <>
      <h5 className="m-0 flex-grow-1">
        {courseLink !== undefined ? (
          <a href={courseLink} target="_blank" rel="noopener noreferrer">
            <span>
              {courseName}
              {courseSupNum || ""} {courseCode}
            </span>
            {genIconDirect("fa-external-link-alt")}
            {courseSuffix}
          </a>
        ) : (
          <span>
            {courseName}
            {courseSupNum || ""} {courseCode}
            {courseSuffix}
          </span>
        )}
      </h5>
      {courseLabelPrefixClass ? (
        <span className={"badge dark mx-1 " + courseLabelPrefixClass}>
          {courseLabelPrefix}
        </span>
      ) : (
        <span className="badge dark mx-1 bg-blue">{courseLabelPrefix}</span>
      )}
      {courseLabelClass ? (
        <span className={"badge dark mx-1 " + courseLabelClass}>
          {courseLabel}
        </span>
      ) : (
        <span className="badge dark mx-1 bg-gold">{courseLabel}</span>
      )}
    </>
  );
  const curriculumPanelCourse_cardBody = (
    <>
      {courseDescription || courseDescriptionJSX ? (
        <div
          className={"card-body text-left p-1 "}
          id={
            "sgsmuscis_curriculum_course_collapse_" +
            textRegexClean(courseName, "underscore")
          }
        >
          {courseDescription === undefined ? (
            ""
          ) : (
            <div className="p-1 padding-5 pull-left">
              <TextHTMLDirectFilter textIn={courseDescription} />
            </div>
          )}
          {courseDescriptionJSX === undefined ? (
            ""
          ) : (
            <>{courseDescriptionJSX}</>
          )}
        </div>
      ) : (
        ""
      )}
    </>
  );

  const courseCardAccordion = (
    <>
      {courseCardCollapse ? (
        <Accordion
          id={
            "CurriculumPanelCourse_" + textRegexClean(courseName, "underscore")
          }
          AccordionContent={[
            {
              headerJSX: <>{curriculumPanelCourse_cardHeader}</>,
              bodyJSX: <>{curriculumPanelCourse_cardBody}</>,
            },
          ]}
          cssAccordion={"sgsmuscis-ug-curriculum-accordion"}
          cssAccordionItem={"card border-dark-subtle my-1"}
          cssAccordionHeader={"bg-transparent flex-grow-1 p-0 m-0"}
          // cssAccordionButton={' '}
          cssAccordionBody={"card-body p-1"}
        />
      ) : (
        <div
          key={uuidv4()}
          id={
            "CurriculumPanelCourse_" + textRegexClean(courseName, "underscore")
          }
          className={
            "card my-1 " +
            (courseCardClass !== undefined
              ? courseCardClass
              : "border-dark-subtle ")
          }
        >
          <div className="card-header d-flex align-items-center p-2 text-left">
            {curriculumPanelCourse_cardHeader}
          </div>
          <>{curriculumPanelCourse_cardBody}</>
        </div>
      )}
    </>
  );
  // console.log(courseCodeProcessed)
  return (
    <div
      key={uuidv4()}
      data-sgsmuscis={"course-code:'" + courseCodeAsDataAttribute + "'"}
    >
      {courseDescription !== undefined || courseDescriptionJSX !== undefined ? (
        <>{courseCardAccordion}</>
      ) : (
        <div
          key={uuidv4()}
          className={"card mb-1 p-1 text-left " + courseCardClass}
        >
          {courseLink !== undefined ? (
            <a href={courseLink} target="_blank" rel="noopener noreferrer">
              <p className="m-0 d-flex align-items-center">
                <span className="flex-grow-1">
                  {courseName} {courseSupNum || ""} {courseCode}{" "}
                  {genIconDirect("fa-external-link-alt")} {courseSuffix}{" "}
                </span>
                <span className="badge dark mx-1 bg-dark-subtle">
                  {courseLabel}
                </span>
              </p>
            </a>
          ) : (
            <p className="m-0 d-flex align-items-center">
              <span className="flex-grow-1">
                {courseName} {courseSupNum || ""} {courseCode}{" "}
                {courseSuffix}{" "}
              </span>
              <span className="badge dark mx-1 bg-dark-subtle">
                {courseLabel}
              </span>
            </p>
          )}
        </div>
      )}
    </div>
  );
};

export default CurriculumPanelCourse;
