// import insane from "insane";
import DOMPurify from "dompurify";

const TextHTMLDirectFilter = (props) => {
  const { textIn, viewMODE } = props;
  const sanitizedHTML = DOMPurify.sanitize(textIn);
  /*
  const sanitizedHTML = insane(textIn, {
    allowedAttributes: {
      a: ['href', 'class', 'target'],
      img: ['src', 'width', 'class'],
      br: ['class'],
      h4: ['class'],
      i: ['class'],
      ul: ['class'],
      p: ['class'],
    }
    })
    */

  return viewMODE === "inline" ? (
    <span dangerouslySetInnerHTML={{ __html: sanitizedHTML }} />
  ) : (
    <div dangerouslySetInnerHTML={{ __html: sanitizedHTML }} />
  );
};

export default TextHTMLDirectFilter;
