export default function arraySubkeyRegexMatch (arrayIn, key, matchString) {
  const r = []
  // console.log('key:', key)
  // console.log('matchString:', matchString)
  for (var k = 0; k < arrayIn.length; k++) {
    const t = new RegExp(matchString, 'g')
    // console.log('item:', arrayIn[k])
    if (arrayIn[k][key].match(t)) {
      r.push(arrayIn[k])
    } else {
      continue
    }
  }
  return r
}
