export default function universalFilter(
  processor,
  selectAREA,
  selectSUBCLASS,
  selectSTATUS,
  selectUSERNAME,
  numberITEMSEACH
) {
  return processor
    .filter((entry) => {
      if (selectAREA && selectSUBCLASS && selectSTATUS) {
        // console.log('selectAREA && selectSUBCLASS && selectSTATUS')
        return (
          entry.datatype === selectAREA &&
          entry[selectSUBCLASS.split("|")[0]] ===
            selectSUBCLASS.split("|")[1] &&
          entry.labels_status === selectSTATUS
        );
      } else if (selectAREA && selectSUBCLASS) {
        // console.log('selectAREA && selectSUBCLASS ')
        return (
          entry.datatype === selectAREA &&
          entry[selectSUBCLASS.split("|")[0]].match(
            new RegExp(selectSUBCLASS.split("|")[1], "g")
          )
        );
      } else if (selectAREA && selectUSERNAME) {
        // console.log('selectAREA && selectUSERNAME ')
        return (
          entry.datatype === selectAREA && entry.id_ntlogin === selectUSERNAME
        );
      } else if (selectAREA && selectSTATUS) {
        // console.log('selectAREA && selectSTATUS ')
        return (
          entry.datatype === selectAREA && entry.labels_status === selectSTATUS
        );
      } else if (selectAREA) {
        // console.log('selectAREA ')
        return entry.datatype === selectAREA;
      } else if (selectSUBCLASS && selectSTATUS) {
        // console.log('selectSUBCLASS && selectSTATUS ')
        return (
          entry[selectSUBCLASS.split("|")[0]].match(
            new RegExp(selectSUBCLASS.split("|")[1], "g")
          ) && entry.labels_status === selectSTATUS
        );
      } else if (selectSUBCLASS) {
        // console.log('selectSUBCLASS ')
        return entry[selectSUBCLASS.split("|")[0]].match(
          new RegExp(selectSUBCLASS.split("|")[1], "g")
        );
      } else if (selectSTATUS) {
        // console.log('selectSTATUS ')
        return entry.labels_status === selectSTATUS;
      } else if (selectUSERNAME) {
        // console.log('selectUSERNAME ')
        return entry.id_ntlogin === selectUSERNAME;
      } else {
        return entry;
      }
    })
    .slice(0, numberITEMSEACH !== "" ? numberITEMSEACH : processor.length);
}
