// import 'es6-shim'
import "regenerator-runtime/runtime";

import React from "react";
import { createRoot } from "react-dom/client";
import { createBrowserHistory } from "history";

import SCISReactUniversalisTXU from "./SCISReactUniversalisTXU";

const historic = createBrowserHistory();

const loadSCISReactUniversalisTXU = (e) => {
  const DOMElementsMetasgSMUSCISReactUQ = document.querySelectorAll(
    "meta[name='sgSMUSCISReactUQ']",
  );
  let loadJSONfrRed = false;
  if (DOMElementsMetasgSMUSCISReactUQ.length > 0) {
    for (let i = 0; i < DOMElementsMetasgSMUSCISReactUQ.length; i++) {
      x = DOMElementsMetasgSMUSCISReactUQ[i]; // console.log(x);
      if (x.attributes.name.value === "sgSMUSCISReactUQ") {
        if (x.attributes.url_origin.value === "red-smu-edu-sg") {
          if (x.attributes.loaded !== undefined) {
            if (
              x.attributes.loaded.value === "true" &&
              x.attributes.status.value !== "void"
            ) {
              loadJSONfrRed = true;
            }
          }
        } else if (x.attributes.url_origin.value === "sgsmuscis-github-io")
          if (x.attributes.loaded !== undefined) {
            if (
              x.attributes.loaded.value === "true" &&
              x.attributes.status.value !== "void"
            ) {
              loadJSONfrRed = false;
            }
          } else {
            console.log("[sgSMUSCISReactUQ] ce59eaad76a848a6a88cfbbf0536f7be");
          }
      }
    }
  } else {
    console.log("[sgSMUSCISReactUQ] ecb1ad788a41482fab381c6c4cf8b846");
  }

  const DOMElementsReactAppRoot =
    document.getElementsByClassName("react-app-root");
  Array.prototype.map.call(DOMElementsReactAppRoot, function (elem) {
    const container = elem;
    const options = {
      selectDATATYPE:
        elem.attributes.selectdatatype !== undefined
          ? elem.attributes.selectdatatype.value
          : "",
      selectCLASS:
        elem.attributes.selectclass !== undefined
          ? elem.attributes.selectclass.value
          : "",
      selectSUBCLASS:
        elem.attributes.selectsubclass !== undefined
          ? elem.attributes.selectsubclass.value
          : "",
      selectSUBTYPES:
        elem.attributes.selectsubtypes !== undefined
          ? elem.attributes.selectsubtypes.value
          : "",
      selectUSERNAME:
        elem.attributes.selectusername !== undefined
          ? elem.attributes.selectusername.value
          : "",
      selectUSERNAMES:
        elem.attributes.selectusernames !== undefined
          ? elem.attributes.selectusernames.value
          : "",
      selectSTATUS:
        elem.attributes.selectstatus !== undefined
          ? elem.attributes.selectstatus.value
          : "",
      selectAREA:
        elem.attributes.selectarea !== undefined
          ? elem.attributes.selectarea.value
          : "",
      viewMODE:
        elem.attributes.viewmode !== undefined
          ? elem.attributes.viewmode.value
          : "",
      numberITEMSEACH:
        elem.attributes.numberitemseach !== undefined
          ? elem.attributes.numberitemseach.value
          : "",
      dataJSONMIRROR: loadJSONfrRed
        ? "a99627d2654"
        : elem.attributes.datajsonmirror !== undefined
          ? elem.attributes.datajsonmirror.value
          : "",
      headersText:
        elem.attributes.headerstext !== undefined
          ? elem.attributes.headerstext.value
          : "",
      linksLabel:
        elem.attributes.linksLabel !== undefined
          ? elem.attributes.linksLabel.value
          : "",
      queryTransfer: false,
    };
    const root = createRoot(container);
    root.render(
      <SCISReactUniversalisTXU options={options} historic={historic} />,
    );
  });
};

document.addEventListener("DOMContentLoaded", function (e) {
  loadSCISReactUniversalisTXU();
});
document.addEventListener("sgSMUSCISReactUQ", function (e) {
  loadSCISReactUniversalisTXU();
});
