import DOMPurify from "dompurify";
import TextHTMLDirectFilter from "./TextHTMLDirectFilter";

const BBStyleCodeProcessor = (props) => {
  const { textIn, viewMODE } = props;
  const sanitizedHTML = DOMPurify.sanitize(textIn);
  const processTEXT = sanitizedHTML
    .replace(/\[headline]/g, "<h3>")
    .replace(/\[\/headline]/g, "</h3>")
    .replace(
      /\[title-dyellow]/g,
      '<h4 class="text-originalcase text-yellow-dark">',
    )
    .replace(/\[\/title-dyellow]/g, "</h4>")
    .replace(/\[title]/g, "<h4>")
    .replace(/\[\/title]/g, "</h4>")
    .replace(/\[subtitle]/g, '<p class="m-0"><strong>')
    .replace(/\[\/subtitle]/g, "</strong></p>")
    .replace(/\[bold]/g, "<strong>")
    .replace(/\[\/bold]/g, "</strong>")
    .replace(/\[block]/g, '<div class="">')
    .replace(/\[\/block]/g, "</div>")
    .replace(/\[para]/g, '<p class="mb-1">')
    .replace(/\[\/para]/g, "</p>")
    .replace(/\[break]/g, '<br class="hidden-xs hidden-sm"/>')
    .replace(/\[separator]/g, "<hr/>")
    .replace(/\[line]/g, "- ")
    .replace(/\[\/line]/g, "<br/>")
    .replace(/\[link]/g, "<a ")
    .replace(/\[\/link]/g, "</a>")
    .replace(/\[simpleurl]/g, 'href="')
    .replace(
      /\[\/simpleurl]/g,
      '" class="text-underline-dotted text-yellow-dark invert" rel="noopener noreferrer">',
    )
    .replace(/\[simpleurl-window]/g, 'href="')
    .replace(
      /\[\/simpleurl-window]/g,
      '" class="text-underline-dotted text-yellow-dark invert" rel="noopener noreferrer" target="_blank">',
    )
    .replace(/\[url]/g, 'href="')
    .replace(
      /\[\/url]/g,
      '" class="btn  btn-sgsmuscis SISBTNMOD SISBTNMOD-LG p-2 m-1 w-100" rel="noopener noreferrer">',
    )
    .replace(/\[definition]/g, "")
    .replace(
      /\[new]/g,
      '<sup style="color: darkblue"><strong>NEW</strong></sup></span>',
    );
  const inputTEXTARRAYSUBLIST = processTEXT.split("[/sublist]");
  const outputTEXTARRAYSUBLIST = inputTEXTARRAYSUBLIST.map(
    function (itemTEXTARRAY) {
      return itemTEXTARRAY.match(/\[sublist]/g)
        ? itemTEXTARRAY
            .replace(/[|]/g, "</li><li class='py-1 m-0'>")
            .replace(/\[sublist]/g, '<ul class="m-0"><li class="py-1 m-0">') +
            "</li></ul>"
        : itemTEXTARRAY;
    },
  );
  const inputTEXTARRAYLIST = outputTEXTARRAYSUBLIST.join("").split("[/list]");
  const output = inputTEXTARRAYLIST.map(function (itemTEXTARRAY) {
    return itemTEXTARRAY.match(/\[list]/g)
      ? itemTEXTARRAY
          .replace(/[|]/g, "</li><li class='py-1 m-0'>")
          .replace(/\[list]/g, '<ul class="m-0"><li class="py-1 m-0">') +
          "</li></ul>"
      : itemTEXTARRAY;
  });

  return <TextHTMLDirectFilter textIn={output.join("")} viewMODE={viewMODE} />;
};

export default BBStyleCodeProcessor;
