import { v4 as uuidv4 } from "uuid";
import React from "react";
import { OverlayTrigger, Tooltip } from "react-bootstrap";
import IntegratedProfile from "./IntegratedProfile";
import {
  getProfileStream,
  TextHTMLDirectFilter,
  universalFilter,
} from "../common";

const IntegratedProfiles = (props) => {
  const {
    // token,
    tokenList,
    viewFormat,
    // viewFormatCleanNoBG,
    viewFormatNoLinks,
    selectAREA,
    selectSTATUS,
    selectSUBCLASS,
    selectUSERNAME,
    numberITEMSEACH,
    historic,
    TaxonomyResAreasStream,
    TaxonomyResAreasStreamNX,
    // Publications,
    Profiles,
    labelLink,
  } = props;

  if (tokenList) {
    // console.log(tokenList)

    const processedView = tokenList
      .replace(/ [|] /g, "|")
      .split("|")
      .map((split_token) => {
        let designationAppend = "";
        if (
          split_token.match(/(\((.*)\))/g) &&
          !split_token.match(new RegExp("{tooltip}", "g"))
        ) {
          designationAppend = split_token.split(" (")[1]
            ? split_token.split(" (")[1].split(")")[0]
            : "";
          split_token = split_token.split(" (")[0];
        }
        // console.log('before:', split_token)
        if (split_token.match(/(\])/g)) {
          split_token = split_token.split(" ")[0];
        }
        // console.log('after::', split_token)
        // console.log(designationAppend)
        // console.log(viewFormat)
        // console.log(selectedProfile)
        // console.log(historic)
        // console.log('|' + selectedProfile.id_ntlogin + '| split_token: "' + split_token + '"')
        const selectedProfile = getProfileStream(split_token, Profiles);
        if (selectedProfile) {
          return (
            <IntegratedProfile
              key={uuidv4()}
              historic={historic}
              profile={selectedProfile}
              taxonomyResAreasStream={TaxonomyResAreasStream}
              taxonomyResAreasStreamNX={TaxonomyResAreasStreamNX}
              // publications={Publications}
              designationAppend={designationAppend}
              viewFormat={viewFormat}
              labelLink={labelLink}
            />
          );
        } else {
          let determineReturn;
          if (split_token === "[advisor]") {
            determineReturn = (
              <strong>
                <br />
                Research Advisor:{" "}
              </strong>
            );
          } else if (split_token === "[co-advisor]") {
            determineReturn = (
              <strong>
                <br />
                Co-Research Advisor:{" "}
              </strong>
            );
          } else if (split_token === "[members]") {
            determineReturn = (
              <strong>
                <br />
                Dissertation Committee Member(s):{" "}
              </strong>
            );
          } else if (split_token === "[external]") {
            determineReturn = (
              <strong>
                <br />
                External Member(s):{" "}
              </strong>
            );
          } else if (split_token === "[external-exam]") {
            determineReturn = (
              <strong>
                <br />
                External Examiner(s):{" "}
              </strong>
            );
          } else if (split_token === "[industry-co-sup]") {
            determineReturn = (
              <strong>
                <br />
                Industry Co-Supervisor(s):{" "}
              </strong>
            );
          } else if (split_token === "[industry-members]") {
            determineReturn = (
              <strong>
                <br />
                Industry Committee Member(s):{" "}
              </strong>
            );
          } else if (split_token.match(new RegExp("{tooltip}", "g"))) {
            // console.log('test tooltip', split_token)
            let inner_ct = split_token
              .replace("{/tooltip}", "")
              .split("{tooltip}");
            // console.log(inner_ct)
            determineReturn = (
              <li
                style={
                  viewFormat.match(/(inline)/g)
                    ? { display: "inline", padding: "0", margin: "0" }
                    : {}
                }
              >
                <TextHTMLDirectFilter textIn={inner_ct[0]} viewMODE="inline" />
                {designationAppend ? " (" + designationAppend + ")" : ""}
                <OverlayTrigger
                  placement="bottom"
                  overlay={
                    <Tooltip id={"tooltip" + uuidv4()}>{inner_ct[1]}</Tooltip>
                  }
                >
                  <i className={"fas fa-info-circle"} />
                </OverlayTrigger>
                {viewFormat.match(/(inline)/g) ? "; " : ""}
              </li>
            );
          } else if (split_token.match(/(@SMU)/g)) {
            const cleanTokenAsQuery = split_token
              .replace(/(_)/g, "%20")
              .replace("[", "")
              .replace("@SMU]", "");
            const cleanTokenAsString = split_token
              .replace(/(_)/g, " ")
              .replace("[", "")
              .replace("@SMU]", "");
            determineReturn = (
              <li
                style={
                  viewFormat.match(/(inline)/g)
                    ? { display: "inline", padding: "0", margin: "0" }
                    : {}
                }
              >
                <a
                  className="text-underline-dotted text-grey-dark yellow invert"
                  href={
                    "https://faculty.smu.edu.sg/?faculty%5Bquery%5D=" +
                    cleanTokenAsQuery
                  }
                  target="_blank"
                >
                  Dr. {cleanTokenAsString}, SMU Faculty
                </a>
              </li>
            );
          } else {
            determineReturn = (
              <li
                style={
                  viewFormat.match(/(inline)/g)
                    ? { display: "inline", padding: "0", margin: "0" }
                    : {}
                }
              >
                <TextHTMLDirectFilter textIn={split_token} viewMODE="inline" />
                {designationAppend ? " (" + designationAppend + ")" : ""}
                {viewFormat.match(/(inline)/g) ? "; " : ""}
              </li>
            );
          }
          return determineReturn;
        }
      });

    return (
      <>
        {!viewFormat.match(/(buttons)/g) ? (
          viewFormat.match(/(inline)/g) ? (
            <ul style={{ display: "inline", padding: "0", margin: "0" }}>
              {processedView}
            </ul>
          ) : (
            <ul className="ps-3" style={{ margin: "0" }}>
              {processedView}
            </ul>
          )
        ) : (
          <span>{processedView}</span>
        )}
      </>
    );
  } else {
    //  const profilesShuffled = (viewFormat.match(/(shuffle)/g)) ? arrayShuffle(Profiles) :
    const processedFiltered = universalFilter(
      Profiles,
      selectAREA,
      selectSUBCLASS,
      selectSTATUS,
      selectUSERNAME,
      numberITEMSEACH,
    );
    // console.log(processedFiltered)
    const processedFilteredMapped = processedFiltered.map((profile) => {
      // console.log(historic)
      // console.log(viewFormat, viewFormat.match(/(NoBG)/g))
      // console.log({Publications})
      return profile.labels_status !== "" ? (
        <IntegratedProfile
          key={uuidv4()}
          historic={historic}
          profile={profile}
          profiles={Profiles}
          taxonomyResAreasStream={TaxonomyResAreasStream}
          taxonomyResAreasStreamNX={TaxonomyResAreasStreamNX}
          // publications={Publications}
          viewFormat={viewFormat}
          viewFormatCleanNoBG={viewFormat.match(/(NoBG)/g)}
          viewFormatMiniClean={viewFormat.match(/(mini)/g)}
          viewFormatMiniCleanNoResLinks={viewFormat.match(/(miniNoResLinks)/g)}
          viewFormatNoLinks={
            viewFormat.match(/(NoLinks)/g) || viewFormatNoLinks
          }
        />
      ) : (
        ""
      );
    });
    return viewFormat.match(/(discomm)/g) ? (
      <>{processedFilteredMapped}</>
    ) : (
      <div className="row align-items-bottom justify-content-left">
        {processedFilteredMapped}
      </div>
    );
  }
};
export default IntegratedProfiles;
