import { v4 as uuidv4 } from "uuid";
import { useEffect, useState } from "react";
import { Form as BSForm } from "react-bootstrap";

import CurriculumPanelMajorCore from "./CurriculumPanelMajorCore";
import CurriculumPanelMajorElectives from "./CurriculumPanelMajorElectives";
import CurriculumPanelSMUCore from "./CurriculumPanelSMUCore";

import CurriculumMajorSecond from "./CurriculumMajorSecond";

import { cLog } from "../../common";

import {
  SMUSCISPROGRAMMES,
  genBSColumns,
  genIconDirect,
  link_SMU_OASIS_BOSS,
  tracks2026Map as tracks2025Map,
} from "../../common/constants";

const CurriculumIntegrated = (props) => {
  const {
    historic,
    viewMODE,
    dataProgrammesThemesTracks,
    dataProgrammesCourses,
    facultyList,
    // queryTransfer,
  } = props;
  const [selectedFeatures, setFeatures] = useState([]);
  const [selectedMajorElectivesOptions, setMajorElectivesOptions] = useState(
    [],
  );
  const [selectedSecondMajor, setSecondMajor] = useState("");
  const [selectedSecondMajorTrackOption, setSecondMajorTrackOption] = useState(
    [],
  );

  const isSMT22a = viewMODE.match(/(b45441be9)/g);
  const isCL = viewMODE.match(new RegExp("CL2022", "g"));
  const isFf4ca540 = viewMODE.match(/(c54681a11)/g);

  const feature_test_mode = viewMODE.match(/(z7kxjyucvp)/g);
  const feature_test_secondMajors = selectedFeatures.includes("ea0ed5e586");
  const feature_test_dbct = selectedFeatures.includes("a318b7e74f");

  const feature_dev_mode = viewMODE.match(/(be768cf7c5)/g);
  const feature_dev_secondMajorsShift = selectedFeatures.includes("d018a38f97");

  useEffect(() => {
    if (feature_test_mode) {
      setFeatures(["ea0ed5e586", "a318b7e74f"]);
    } else if (feature_dev_mode) {
      setFeatures(["ea0ed5e586", "a318b7e74f", "d018a38f97"]); //, "u9OFXsP61l"
    } else {
      // do nothing
    }
  }, []);

  const arrayRemoveElem = (arr, elem) => {
    return arr.filter((e) => e !== elem);
  };
  const handleFeatures = (k) => {
    cLog(["before selectedFeatures", selectedFeatures], feature_test_mode);
    // setFeatures(k.target.value);
    let newSt = [...selectedFeatures];
    if (k.target) {
      if (newSt.includes(k.target.value)) {
        newSt = arrayRemoveElem(newSt, k.target.value);
      } else {
        newSt.push(k.target.value);
      }
    } else {
      if (newSt.includes(k)) {
        newSt = arrayRemoveElem(newSt, k);
      } else {
        newSt.push(k);
      }
    }
    cLog(["handleFeatures", selectedFeatures], feature_test_mode);
    cLog(["after selectedFeatures", selectedFeatures], feature_test_mode);
    setFeatures(newSt);
  };
  const handleSelection_secondMajor = (k) => {
    cLog(["handleSelection_secondMajor", k], feature_test_mode);
    k = k.target ? (k.target.value ? k.target.value : k) : k;
    setSecondMajor(selectedSecondMajor === k || k === "RESET" ? "" : k);
    setSecondMajorTrackOption([]);
  };
  const handleSelection = (index) => {
    let newState = [...selectedMajorElectivesOptions];
    // console.log("before selectedMajorElectivesOptions newState :" + newState);
    if (index === "reset") {
      newState = [];
    } else {
      if (newState.length < 2) {
        if (newState.includes(index)) {
          newState = arrayRemoveElem(newState, index);
        } else {
          if (index < 7) {
            newState.push(index);
          } else if (newState.length === 1) {
            newState.push(index);
          } else {
            // do nothing : as 2nd major, etc. can only be second option
          }
        }
      } else {
        if (index < 7 && newState[1] < 7) {
          newState = arrayRemoveElem(newState, index);
        } else if (index > 6 && newState[1] > 6) {
          newState = arrayRemoveElem(newState, index);
        } else if (index < 7 && newState[1] > 6) {
          newState = [];
        } else {
          // do nothing
        }
      }
    }
    // console.log("after selectedMajorElectivesOptions newState :" + newState);
    setMajorElectivesOptions(newState);
  };
  const handleSelection_secondMajorTrackOptions = (index) => {
    let newState = [...selectedSecondMajorTrackOption];
    // console.log("before selectedSecondMajorTrackOption newState :" + newState);
    if (index === "reset") {
      newState = [];
    } else {
      if (newState.length < 1) {
        if (newState.includes(index)) {
          newState = arrayRemoveElem(newState, index);
        } else {
          if (index < 7) {
            newState.push(index);
          } else if (newState.length === 1) {
            newState.push(index);
          } else {
            // do nothing : as 2nd major, etc. can only be second option
          }
        }
      } else {
        if (index < 7 && newState[0] < 7) {
          newState = arrayRemoveElem(newState, index);
        } else if (index > 6 && newState[0] > 6) {
          newState = arrayRemoveElem(newState, index);
        } else if (index < 7 && newState[0] > 6) {
          newState = [];
        } else {
          // do nothing
        }
      }
    }
    // console.log("after selectedSecondMajorTrackOption newState :" + newState);
    setSecondMajorTrackOption(newState);
  };
  // [TODO] START | revert to const !!!TEMPORARY HACKY | (NEED TO ADD U2XeCSbeCeVT INTO GSHEET CS CORE MODS)
  let iViewMODE;
  console.log("viewMODE:", viewMODE);
  if (viewMODE.match(/(U2XeCSbeCeVT)/g)) {
    iViewMODE = viewMODE.replace(/(U2XeCSbeCeVT)/g, "CS2019");
  } else if (viewMODE.match(/(iSBnkwaOwIxvIPM)/g)) {
    iViewMODE = viewMODE.replace(/(iSBnkwaOwIxvIPM)/g, "CS2026");
  } else {
    iViewMODE = viewMODE;
  }
  console.log("iViewMODE:", iViewMODE);
  // [TODO] END   |  revert to const !!!TEMPORARY HACKY

  const procCourseProgMR = (k, j) => {
    const arr = k.split(",");
    return arr.some((e) => {
      // const trimmedValue = e.replace(/^[^:]*:(.*?)([ :])$/, "$1");
      const iViewMODE =
        viewMODE.match(/(U2XeCSbeCeVT)/g) ||
        viewMODE.match(/(iSBnkwaOwIxvIPM)/g)
          ? viewMODE
              .replace(/(U2XeCSbeCeVT)/g, "CS2019")
              .replace(/(iSBnkwaOwIxvIPM)/g, "CS2019")
          : viewMODE;
      const detShow =
        e.length > 0
          ? e.includes(":")
            ? selectedMajorElectivesOptions.length > 0
              ? (new RegExp(iViewMODE, "g").test(e) &&
                  new RegExp(
                    `#${tracks2025Map[selectedMajorElectivesOptions[0]]}`,
                    "g",
                  ).test(e)) ||
                (new RegExp(iViewMODE, "g").test(e) &&
                  new RegExp(
                    `#${tracks2025Map[selectedMajorElectivesOptions[1]]}`,
                    "g",
                  ).test(e))
              : false
            : new RegExp(iViewMODE, "g").test(e)
          : e.length === 0
            ? true
            : false;

      cLog(
        [
          "procCourseProgMR",
          j,
          "e",
          e,
          // "trimmedValue", trimmedValue,
          "iViewMODE",
          iViewMODE,
          "tracks2025Map[selectedMajorElectivesOptions[0]",
          tracks2025Map[selectedMajorElectivesOptions[0]],
          "tracks2025Map[selectedMajorElectivesOptions[1]",
          tracks2025Map[selectedMajorElectivesOptions[1]],
          "tracks2025Map[selectedSecondMajorTrackOption[0]",
          tracks2025Map[selectedSecondMajorTrackOption[0]],
          "selectedSecondMajor",
          selectedSecondMajor,
          "detShow",
          detShow,
        ],
        feature_test_mode,
      );
      return detShow;
    });
  };
  const dataCoreCoursesExt = dataProgrammesCourses.filter((e) => {
    return (
      e.course_attributes.match(new RegExp("CORE", "g")) &&
      e.programme_meta.match(new RegExp(iViewMODE, "g"))
    );
  });
  // console.log("dataCoreCoursesExt", dataCoreCoursesExt);
  const dataElectivesExtTrackCourses = dataProgrammesCourses.filter((e) => {
    return (
      e.course_attributes.match(new RegExp("ISTC", "g")) &&
      procCourseProgMR(e.course_progMR, e.course_name)
    );
  });
  const dataElectivesExtElectives = dataProgrammesCourses.filter((e) => {
    return (
      e.course_attributes.match(new RegExp("ELECTIVES", "g")) &&
      e.programme_meta.match(new RegExp(viewMODE, "g"))
    );
  }); // SMT22a
  const data2ndMajorCompStudies = dataProgrammesCourses.filter((e) => {
    return (
      e.programme_meta.match(new RegExp("2NDMJR_COMPSTUDIES", "g")) &&
      procCourseProgMR(e.course_progMR, e.course_name)
    );
  });
  const data2ndMajorT4BS = dataProgrammesCourses.filter((e) => {
    return (
      e.programme_meta.match(new RegExp("2NDMJR_T4BS", "g")) &&
      procCourseProgMR(e.course_progMR, e.course_name)
    );
  });
  const data2ndMajorITSM = dataProgrammesCourses.filter((e) => {
    return (
      e.programme_meta.match(new RegExp("2NDMJR_ITSM", "g")) &&
      procCourseProgMR(e.course_progMR, e.course_name)
    );
  });

  const is_fdef180d8041c3a4534 =
    viewMODE.match(/(c31724904a7e)/g) ||
    viewMODE.match(/(U2XeCSbeCeVT)/g) ||
    viewMODE.match(/(CL2022)/g) ||
    viewMODE.match(/(c54681a11)/g);

  const detIntakeYearText =
    viewMODE.match(/(iSBnkwaOwIxvIPM)/g) || viewMODE.match(/CS2026/g)
      ? "For Intake AY2026 onwards"
      : is_fdef180d8041c3a4534
        ? "For Intake AY2025 onwards"
        : "For Intake AY2022 ";
  return (
    <>
      {feature_test_mode || feature_dev_mode ? (
        <div className="card mx-0 my-2 border-dark">
          <div className="card-body p-2">
            <BSForm
              className="d-flex align-items-center justify-content-left"
              onChange={(e) => {
                handleFeatures(e);
              }}
            >
              <strong>
                <i class="fas fa-cog"></i> TEST FEATURES
              </strong>
              <BSForm.Check
                className=" mx-2"
                type="checkbox"
                id="feature_test_secondMajors"
                label="Second majors"
                value="ea0ed5e586"
                checked={selectedFeatures.includes("ea0ed5e586")}
              />
              <BSForm.Check
                className=" mx-2"
                type="checkbox"
                id="feature_test_dbct"
                label="Double-counting"
                value="a318b7e74f"
                checked={selectedFeatures.includes("a318b7e74f")}
              />
              {feature_dev_mode ? (
                <>
                  <BSForm.Check
                    className=" mx-2"
                    type="checkbox"
                    id="feature_dev_secondMajorsShift"
                    label="Second Majors Shift"
                    value="d018a38f97"
                    checked={selectedFeatures.includes("d018a38f97")}
                  />
                  <BSForm.Check
                    className=" mx-2"
                    type="checkbox"
                    id="feature_dev_rmElectivesSel"
                    label="Remove Electives Selection"
                    value="u9OFXsP61l"
                    checked={selectedFeatures.includes("u9OFXsP61l")}
                  />
                  <BSForm.Check
                    className=" mx-2"
                    type="checkbox"
                    id="feature_dev_mjElectivesFtr"
                    label="Track Selection in Footer"
                    value="JEIL1VoehP"
                    checked={selectedFeatures.includes("JEIL1VoehP")}
                  />
                </>
              ) : (
                ""
              )}
            </BSForm>
          </div>
        </div>
      ) : (
        ""
      )}
      <div
        key={uuidv4()}
        className="card"
        id="smu-scis-undergrad-curriculum-structure"
        style={{ border: "solid 2px #c69200" }}
      >
        <div className="card-header px-2 py-1">
          <div className="row align-items-center">
            <div className={genBSColumns("9", "8", "7", "12") + "px-2"}>
              <h4 className="ps-2 m-0 text-dark">
                Bachelor of Science{" "}
                {viewMODE.match(/c31724904a7e/g)
                  ? "(Information Systems) : Information Systems"
                  : ""}
                {viewMODE.match(/b45441be9/g)
                  ? "(Information Systems) : Smart-City Management & Technology"
                  : ""}
                {viewMODE.match(/CS2019/g)
                  ? "(Computer Science) : IT Solution Development"
                  : ""}
                {viewMODE.match(/U2XeCSbeCeVT/g)
                  ? "(Computer Science) : IT Solution Development"
                  : ""}
                {viewMODE.match(/iSBnkwaOwIxvIPM/g)
                  ? "(Computer Science) : AI Solution Development"
                  : ""}
                {viewMODE.match(/CS2026/g)
                  ? "(Computer Science) : AI Solution Development"
                  : ""}
                {viewMODE.match(/c54681a11/g) ? "(Sofware Engineering)" : ""}
                {viewMODE.match(/CL2022/g) ? "(Computing & Law)" : ""}
              </h4>
            </div>
            <div className={genBSColumns("3", "4", "5", "12") + "px-2"}>
              <span className="badge p-2 m-1 bg-blue float-end text-uppercase">
                {detIntakeYearText}
              </span>
            </div>
          </div>
        </div>
        <div className="card-body p-2">
          <div className="row">
            <CurriculumPanelSMUCore
              viewMODE={iViewMODE}
              selectedFeatures={selectedFeatures}
            />
            <div
              className={
                feature_dev_secondMajorsShift
                  ? "col-xl-6 col-lg-6 col-md-6 col-sm-6 col-12"
                  : "col-xl-12 col-lg-12 col-md-12 col-sm-12 col-12"
              }
            >
              <CurriculumPanelMajorCore
                historic={historic}
                viewMODE={iViewMODE}
                dataCoreCourses={dataCoreCoursesExt}
                selectedFeatures={selectedFeatures}
                selectedMajorElectivesOptions={selectedMajorElectivesOptions}
                selectedSecondMajor={selectedSecondMajor}
                selectedSecondMajorTrackOption={selectedSecondMajorTrackOption}
              />
              <CurriculumPanelMajorElectives
                historic={historic}
                viewMODE={viewMODE}
                dataElectives={
                  viewMODE.match(/b45441be9/g)
                    ? dataElectivesExtElectives
                    : dataElectivesExtTrackCourses
                }
                data2ndMajorCompStudies={data2ndMajorCompStudies}
                data2ndMajorT4BS={data2ndMajorT4BS}
                data2ndMajorITSM={data2ndMajorITSM}
                dataCurriculumTracks={dataProgrammesThemesTracks}
                profiles={facultyList}
                selectedFeatures={selectedFeatures}
                selectedMajorElectivesOptions={selectedMajorElectivesOptions}
                selectedSecondMajor={selectedSecondMajor}
                selectedSecondMajorTrackOption={selectedSecondMajorTrackOption}
                handleSelection={handleSelection}
                handleSelection_secondMajor={handleSelection_secondMajor}
                handleSelection_secondMajorTrackOptions={
                  handleSelection_secondMajorTrackOptions
                }
              />
            </div>
            {feature_dev_secondMajorsShift ? (
              <div className="col-xl-6 col-lg-6 col-md-6 col-sm-6 col-12">
                <CurriculumMajorSecond
                  historic={historic}
                  viewMODE={viewMODE}
                  dataElectives={dataElectivesExtTrackCourses}
                  dataCurriculumTracks={dataProgrammesThemesTracks}
                  data2ndMajorCompStudies={data2ndMajorCompStudies}
                  data2ndMajorT4BS={data2ndMajorT4BS}
                  data2ndMajorITSM={data2ndMajorITSM}
                  profiles={facultyList}
                  selectedFeatures={selectedFeatures}
                  selectedMajorElectivesOptions={selectedMajorElectivesOptions}
                  selectedSecondMajor={selectedSecondMajor}
                  selectedSecondMajorTrackOption={
                    selectedSecondMajorTrackOption
                  }
                  handleSelection_secondMajor={handleSelection_secondMajor}
                  handleSelection_secondMajorTrackOptions={
                    handleSelection_secondMajorTrackOptions
                  }
                />
              </div>
            ) : (
              ""
            )}
          </div>
        </div>
        <div className="card-footer px-2 py-1">
          <div className="row align-items-center">
            <div className={genBSColumns("9", "8", "7", "12") + "px-2"}>
              <ul className="ps-3 m-0" style={{ fontSize: "14px" }}>
                {feature_test_secondMajors && feature_test_dbct ? (
                  <>
                    <li className="p-0">
                      <span className="badge bg-success px-2">^</span> Indicates
                      double-counting possibilities, which may vary based on the
                      chosen track options and the second major selected.
                    </li>
                    <li className="p-0">
                      <span className="badge bg-info px-2">*</span> These are
                      the remaining required CUs under Free Electives that will
                      contribute to the minimum required 36 CUs. Typically, 8
                      CUs are needed for all SCIS second majors. With SCIS
                      second majors and double-counting, it is possible to
                      complete within 36 CUs. C{link_SMU_OASIS_BOSS} or their
                      respective program managers for guidance.
                    </li>
                  </>
                ) : (
                  ""
                )}
                <li className="p-0">
                  <sup>1</sup> SMU Core Curriculum Basket of Courses. See{" "}
                  <a href={SMUSCISPROGRAMMES.UG.SMUCORE.url} target="_blank">
                    SMU Core Curriculum {genIconDirect("fa-external-link-alt")}
                  </a>{" "}
                  website for more details.{" "}
                </li>
                {isFf4ca540 ? (
                  <li className="p-0">
                    <span className="p-0 m-0" style={{ fontSize: "14px" }}>
                      <sup>2</sup>{" "}
                      {
                        SMUSCISPROGRAMMES.c54681a11.curriculumStack
                          .Apprenticeship.internshipNote
                      }
                      .
                    </span>
                  </li>
                ) : (
                  ""
                )}
                <li className="p-0">
                  {isCL ? <sup>2</sup> : ""} C{link_SMU_OASIS_BOSS}.
                </li>
                <li className="p-0">
                  Curriculum details primarily serve as a guide. Course listings
                  are non-exhaustive and subject to changes.
                </li>
              </ul>
            </div>
            <div className={genBSColumns("3", "4", "5", "12") + "px-2"}>
              <span className="badge p-2 m-1 bg-gold float-end">
                TOTAL: 36 Credit Units (CUs)
              </span>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default CurriculumIntegrated;
